script:
export const meta = {
  name: 'pass5-confirm',
  description: 'Pass-5: 2-agent confirmation that each fix is appropriate AND complete',
  phases: [{ title: 'Confirm' }, { title: 'Tally' }],
}
const ROOT='/Users/thomasjones/hc-assay'
const FIXES=[{"id": "H-001", "file": "src/assay_engine/methodology/{hypothesis,confirm}.py + preregistration.py", "what": "alpha & stability_threshold are optional digest-bound Hypothesis fields; confirmers cross-check confirm-time args against locked values (mismatch raises) \u2014 closes threshold HARKing.", "test": "test_locked_alpha_cannot_be_overridden_at_confirm_time, test_locked_stability_threshold_cannot_be_overridden_at_confirm_time, test_digest_covers_content_and_id_but_not_lock_fields"}, {"id": "H-002", "file": "src/assay_engine/methodology/confirm.py", "what": "`powered` recorded in verdict evidence + documented as a trusted caller obligation.", "test": "test_powered_flag_is_recorded_in_evidence"}, {"id": "H-003", "file": "src/assay_engine/methodology/confirm.py", "what": "documented test_name is bound for audit but engine can't verify the executed test (caller obligation).", "test": "(doc; no test)"}, {"id": "H-004", "file": "src/assay_engine/reasoning/seam.py", "what": "malformed reasoning params (temperature/seed) raise typed PermanentReasoningError, not raw ValueError/TypeError.", "test": "test_malformed_params_raise_typed_permanent_error"}, {"id": "H-007", "file": "scripts/license_gate.py", "what": "UNKNOWN/empty-license packages surfaced as ::warning:: (not silent); gate still fails only on deny matches.", "test": "test_license_gate_surfaces_unknown_licenses"}, {"id": "H-008", "file": ".github/workflows/ci.yml", "what": "top-level permissions: contents: read (least privilege for GITHUB_TOKEN).", "test": "test_ci_has_least_privilege_permissions"}, {"id": "H-009", "file": ".github/workflows/ci.yml", "what": "integration job verifies Postgres/Qdrant reachable (pg_isready + /readyz) so live tests can't silently skip.", "test": "test_ci_integration_verifies_services_are_reachable"}, {"id": "H-010", "file": "src/assay_engine/baseline/determinism.py", "what": "stable_seed docstring corrected: truncated seed gives uniqueness only to the birthday bound, not guaranteed.", "test": "(doc; no test)"}, {"id": "H-011", "file": "src/assay_engine/orchestration/gatenode.py", "what": "documented the deliberate recorder-optionality asymmetry vs run_study (runner owns+always records).", "test": "(doc; no test)"}, {"id": "H-012", "file": "src/assay_engine/orchestration/gatenode.py", "what": "scoped the 'atomically'/'terminal idempotency' docstring claims honestly.", "test": "(doc; no test)"}, {"id": "H-013", "file": "src/assay_engine/pipeline.py", "what": "provenance-trail artifact tempfile unlinked after tracker copies it (was leaked per run).", "test": "test_tracker_receives_run_and_metrics_and_failures_dont_abort (asserts temp gone)"}, {"id": "H-015", "file": "src/assay_engine/methodology/confirm.py", "what": "documented unit-level intentionally lacks whole-corpus's directionless-lock refusal (direction is advisory there).", "test": "(doc; no test)"}, {"id": "H-016", "file": "src/assay_engine/methodology/discovery.py", "what": "documented Firewall B is enforced STRUCTURALLY (held-out-only corpus); assert_confirm_only is the study's extra guard.", "test": "(doc; no test)"}, {"id": "H-017", "file": "src/assay_engine/provenance.py", "what": "documented serialized records don't embed keying; verifier supplies the secret out-of-band.", "test": "(doc; no test)"}, {"id": "H-018", "file": "scripts/capture_transcripts.py", "what": "transcript scrubber redacts username in the project-dir slug (-Users-<name>-) at any length.", "test": "test_transcript_scrub_redacts_username_in_project_dir_slug"}, {"id": "H-021", "file": "src/assay_engine/persistence/vectorstore.py", "what": "query rejects k<=0 and skips returned points lacking 'ref' payload.", "test": "test_vector_store_query_validates_k_and_skips_payloadless_points"}, {"id": "H-022", "file": "src/assay_engine/persistence/vectorstore.py", "what": "_int_env names the bad env var instead of opaque import-time int() error.", "test": "test_int_env_names_the_bad_var"}, {"id": "H-023", "file": "src/assay_engine/persistence/checkpoint.py", "what": "redact_creds docstring corrected: precise only when conn string appears verbatim; regex backstops otherwise.", "test": "(doc; no test)"}, {"id": "H-024", "file": "tests/test_immutability.py", "what": "marked the in-process unfreeze test illustrative; the seed-pinned subprocess test is the discriminating guard.", "test": "test_unfreeze_frozenset_order_is_seed_independent_subprocess"}]
const V={type:'object',required:['fix_id','appropriate','complete','verdict','reasoning'],
  properties:{fix_id:{type:'string'},appropriate:{type:'boolean'},complete:{type:'boolean'},
    verdict:{type:'string',enum:['CONFIRMED','CONCERN']},reasoning:{type:'string'}}}
const pr=(f,n)=>`You are confirmer #${n}, independent. Confirm a production-hardening fix is BOTH appropriate (correct, no regression, idiomatic) AND complete (for a code change the named test must DISCRIMINATE — fail if reverted; for a doc/decision item, judge whether the documented claim is now accurate/honest). Repo ${ROOT}\nFix ${f.id} in ${f.file}\nWhat: ${f.what}\nTest(s): ${f.test}\nRead the actual changed file(s); read the test; check no regression. Verdict CONFIRMED (both true) or CONCERN. Be skeptical and specific.`
phase('Confirm')
const results=await pipeline(FIXES,
  f=>parallel([
    ()=>agent(pr(f,1),{label:'cA:'+f.id,phase:'Confirm',schema:V}),
    ()=>agent(pr(f,2),{label:'cB:'+f.id,phase:'Confirm',schema:V}),
  ]),
  (vs,f)=>{const [a,b]=vs.filter(Boolean); const both=a&&b&&a.verdict==='CONFIRMED'&&b.verdict==='CONFIRMED';
    return {fix_id:f.id,both_confirmed:both,
      a:a?{v:a.verdict,ap:a.appropriate,co:a.complete,why:a.reasoning}:null,
      b:b?{v:b.verdict,ap:b.appropriate,co:b.complete,why:b.reasoning}:null}})
phase('Tally')
const confirmed=results.filter(Boolean).filter(r=>r.both_confirmed)
const concerns=results.filter(Boolean).filter(r=>!r.both_confirmed)
log('CONFIRMED '+confirmed.length+'/'+results.length+'; CONCERNS: '+concerns.map(c=>c.fix_id).join(', '))
return {total:results.length,confirmed_count:confirmed.length,concerns,all:results.filter(Boolean)}
